class TransientError(Exception):
    transient = True

def with_retries(fn, max_attempts=3):
    for attempt in range(max_attempts):
        try:
            return fn()
        except TransientError:
            if attempt == max_attempts - 1:
                raise
    raise RuntimeError("unreachable")

TOOLS = {"search": lambda q: f"hits for {q}"}

good_responses = iter([
    {"stop_reason": "tool_use", "content": [{"type": "tool_use", "id": "t1", "name": "search", "input": {"q": "ramen"}}], "usage": 60},
    {"stop_reason": "end_turn", "content": [{"type": "text", "text": "Found ramen."}], "usage": 70},
])

bad_responses = iter([
    {"stop_reason": "tool_use", "content": [{"type": "tool_use", "id": "b1", "name": "search", "input": {"q": "x"}}], "usage": 80},
    {"stop_reason": "tool_use", "content": [{"type": "tool_use", "id": "b2", "name": "search", "input": {"q": "y"}}], "usage": 100},
])

current = {"iter": good_responses}
def fake_model(messages):
    return next(current["iter"])

def harness(user_input, tools, fake_model, config, max_iters):
    # Layer 1: system_prompt is a top-level kwarg in the Anthropic
    # SDK, NOT a role inside messages. Keep them separate.
    system_prompt = config.get("system")
    system_used = system_prompt is not None
    messages = [{"role": "user", "content": user_input}]

    tool_calls_total = 0
    tokens_used = 0

    for i in range(1, max_iters + 1):
        response = with_retries(lambda: fake_model(messages))
        tokens_used += response.get("usage", 0)

        text_blocks = [b for b in response["content"] if b["type"] == "text"]
        tool_blocks = [b for b in response["content"] if b["type"] == "tool_use"]

        if response["stop_reason"] == "end_turn":
            return {
                "text": " ".join(b["text"] for b in text_blocks),
                "iters": i,
                "tool_calls": tool_calls_total,
                "tokens": tokens_used,
                "system_used": system_used,
            }

        tool_results = []
        for block in tool_blocks:
            output = tools[block["name"]](**block["input"])
            tool_calls_total += 1
            tool_results.append({"type": "tool_result", "tool_use_id": block["id"], "content": output})

        messages.append({"role": "assistant", "content": response["content"]})
        messages.append({"role": "user", "content": tool_results})

    return {
        "text": "capped",
        "iters": max_iters,
        "tool_calls": tool_calls_total,
        "tokens": tokens_used,
        "system_used": system_used,
    }

